(function(w){"use strict";
function e(v){return String(v==null?"":v).replace(/[&<>"']/g,function(c){return {"&":"&amp;","<":"&lt;",">":"&gt;","\"":"&quot;","'":"&#39;"}[c]||c;});}
function renderField(f){var a=' data-key="'+e(f.key)+'"';if(f.raw)a+=' data-raw="1"';if(f.type==='select'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><select class="hm-calc-select"'+a+'>'+f.options.map(function(o){return '<option value="'+e(o[0])+'"'+(String(o[0])===String(f.default)?' selected':'')+'>'+e(o[1])+'</option>';}).join('')+'</select></div>';}if(f.type==='textarea'){return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><textarea class="hm-calc-input" rows="4"'+a+' placeholder="'+e(f.placeholder||'')+'">'+e(f.default||'')+'</textarea></div>';}var type=f.type==='date'?'date':'text';var mode=f.type==='integer'?'numeric':'decimal';return '<div class="hm-calc-field"><label>'+e(f.label)+'</label><input class="hm-calc-input" type="'+type+'" inputmode="'+mode+'"'+a+' placeholder="'+e(f.placeholder||'')+'" value="'+e(f.default||'')+'"></div>';}
function makeRender(def){return function(root,api){var html='<div class="hm-calc-panel"><div class="hm-calc-form">';if(def.hint)html+='<p class="hm-calc-hint">'+e(def.hint)+'</p>';html+='<div class="hm-calc-grid-2">'+def.fields.map(renderField).join('')+'</div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>';root.innerHTML=html;var els=Array.prototype.slice.call(root.querySelectorAll('[data-key]')),go=root.querySelector('button'),msg=root.querySelector('.hm-calc-message'),res=root.querySelector('.hm-calc-result');go.addEventListener('click',function(){var x={};els.forEach(function(el){var k=el.getAttribute('data-key');if(el.tagName==='SELECT'||el.getAttribute('data-raw')==='1'||el.type==='date')x[k]=el.value;else x[k]=api.parseNumber(el.value);});var r=def.compute(x);if(r&&r.error){api.setMessage(msg,r.error);api.clearResult(res);return;}api.setMessage(msg,'');api.setResult(res,def.format(r,api));});};}
var defs=[{id:"clock-work-hours",fields:[{"key":"startHour","label":"출근 시","type":"integer","placeholder":"","default":"9","options":[],"raw":false},{"key":"startMinute","label":"출근 분","type":"integer","placeholder":"","default":"0","options":[],"raw":false},{"key":"endHour","label":"퇴근 시","type":"integer","placeholder":"","default":"18","options":[],"raw":false},{"key":"endMinute","label":"퇴근 분","type":"integer","placeholder":"","default":"0","options":[],"raw":false},{"key":"breakMinutes","label":"휴게시간 (분)","type":"number","placeholder":"","default":"60","options":[],"raw":false}],hint:"",compute:function(x){var sh=Number(x.startHour),sm=Number(x.startMinute),eh=Number(x.endHour),em=Number(x.endMinute),b=Number(x.breakMinutes);if(![sh,sm,eh,em,b].every(Number.isFinite)||sh<0||sh>=24||eh<0||eh>=24||sm<0||sm>=60||em<0||em>=60||b<0)return{error:"시는 0~23, 분은 0~59, 휴게시간은 0 이상으로 입력해 주세요."};var start=sh*60+sm,end=eh*60+em;if(end<start)end+=1440;var gross=end-start,net=gross-b;if(net<0)return{error:"휴게시간이 전체 체류시간보다 깁니다."};return{grossMinutes:gross,netMinutes:net,netHours:net/60,breakMinutes:b};},format:function(r,api){return api.resultCard("실근무 시간",api.formatNumber(r.netHours,2)+"시간",api.formatNumber(r.netMinutes,0)+"분")+api.resultCard("전체 체류시간",api.formatNumber(r.grossMinutes/60,2)+"시간","휴게 "+api.formatNumber(r.breakMinutes,0)+"분");}},{id:"weekly-pay-custom",fields:[{"key":"hourlyRate","label":"시급","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"weeklyHours","label":"주간 근무시간","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"extraPay","label":"주간 추가수당","type":"number","placeholder":"","default":"0","options":[],"raw":false}],hint:"",compute:function(x){var r=Number(x.hourlyRate),h=Number(x.weeklyHours),e=Number(x.extraPay);if(![r,h,e].every(Number.isFinite)||r<0||h<0||e<0)return{error:"시급·근무시간·추가수당은 0 이상으로 입력해 주세요."};var base=r*h,total=base+e;return{basePay:base,totalPay:total,monthlyEstimate:total*52/12};},format:function(r,api){return api.resultCard("예상 주급",api.formatMoney(r.totalPay),"기본급 "+api.formatMoney(r.basePay))+api.resultCard("월 환산 추정",api.formatMoney(r.monthlyEstimate),"52주 ÷ 12개월");}},{id:"biweekly-pay-custom",fields:[{"key":"hourlyRate","label":"시급","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"hoursPerWeek","label":"주당 근무시간","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"extraPay","label":"2주 추가수당","type":"number","placeholder":"","default":"0","options":[],"raw":false}],hint:"",compute:function(x){var r=Number(x.hourlyRate),h=Number(x.hoursPerWeek),e=Number(x.extraPay);if(![r,h,e].every(Number.isFinite)||r<0||h<0||e<0)return{error:"시급·근무시간·추가수당은 0 이상으로 입력해 주세요."};var base=r*h*2,total=base+e;return{basePay:base,totalPay:total,annualEstimate:total*26};},format:function(r,api){return api.resultCard("예상 2주 급여",api.formatMoney(r.totalPay),"기본급 "+api.formatMoney(r.basePay))+api.resultCard("연 환산 추정",api.formatMoney(r.annualEstimate),"연 26회 기준");}},{id:"unpaid-leave-deduction",fields:[{"key":"monthlySalary","label":"월 급여","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"workDaysInMonth","label":"월 소정근무일수","type":"number","placeholder":"","default":"20","options":[],"raw":false},{"key":"unpaidDays","label":"무급휴가 일수","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"회사 규정과 실제 급여 산정방식에 따라 달라질 수 있습니다.",compute:function(x){var s=Number(x.monthlySalary),d=Number(x.workDaysInMonth),u=Number(x.unpaidDays);if(![s,d,u].every(Number.isFinite)||s<0||d<=0||u<0||u>d)return{error:"월 급여는 0 이상, 근무일수는 0보다 크게, 무급일수는 근무일수 이하로 입력해 주세요."};var daily=s/d,deduct=daily*u;return{dailyPay:daily,deduction:deduct,remainingSalary:s-deduct};},format:function(r,api){return api.resultCard("예상 공제액",api.formatMoney(r.deduction),"1일 "+api.formatMoney(r.dailyPay))+api.resultCard("공제 후 급여",api.formatMoney(r.remainingSalary),"");}},{id:"holiday-pay-custom",fields:[{"key":"hourlyRate","label":"시급","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"hours","label":"휴일 근무시간","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"multiplier","label":"수당 배수","type":"number","placeholder":"","default":"1.5","options":[],"raw":false}],hint:"법정 배수와 회사 규정을 확인한 뒤 배수를 직접 입력하세요.",compute:function(x){var r=Number(x.hourlyRate),h=Number(x.hours),m=Number(x.multiplier);if(![r,h,m].every(Number.isFinite)||r<0||h<0||m<0)return{error:"시급·근무시간·배수는 0 이상으로 입력해 주세요."};return{basePay:r*h,holidayPay:r*h*m,premium:r*h*(m-1)};},format:function(r,api){return api.resultCard("휴일근무 수당",api.formatMoney(r.holidayPay),"기본급 상당 "+api.formatMoney(r.basePay))+api.resultCard("가산분",api.formatMoney(r.premium),"");}},{id:"commission-net-sales",fields:[{"key":"grossSales","label":"총매출","type":"number","placeholder":"","default":"","options":[],"raw":false},{"key":"returns","label":"반품·취소액","type":"number","placeholder":"","default":"0","options":[],"raw":false},{"key":"commissionRate","label":"수수료율 (%)","type":"number","placeholder":"","default":"","options":[],"raw":false}],hint:"",compute:function(x){var g=Number(x.grossSales),r=Number(x.returns),p=Number(x.commissionRate);if(![g,r,p].every(Number.isFinite)||g<0||r<0||r>g||p<0)return{error:"매출과 반품액은 0 이상, 반품액은 총매출 이하, 수수료율은 0 이상으로 입력해 주세요."};var net=g-r,c=net*p/100;return{netSales:net,commission:c,remaining:net-c};},format:function(r,api){return api.resultCard("판매수수료",api.formatMoney(r.commission),"순매출 "+api.formatMoney(r.netSales))+api.resultCard("수수료 차감 후",api.formatMoney(r.remaining),"");}}];defs.forEach(function(def){w.HM_CALC.register(def.id,{compute:def.compute,render:makeRender(def)});});})(window);
